1	import mongoose, { Schema, Document, Model } from 'mongoose';
2	import { IUserRoadmapProgress, IUserRoadmapNodeProgress, IUserLessonProgress } from '../types/roadmap.types';
3	
4	const LessonProgressSchema = new Schema<IUserLessonProgress>(
5	  {
6	    lessonId: { type: String, required: true },
7	    readAt: { type: Date }
8	  },
9	  { _id: false }
10	);
11	
12	const NodeProgressSchema = new Schema<IUserRoadmapNodeProgress>(
13	  {
14	    nodeId: { type: String, required: true },
15	    mastered: { type: Boolean, required: true, default: false },
16	    bestScore: { type: Number, required: true, default: 0, min: 0, max: 100 },
17	    lowScoreFailCount: { type: Number, default: 0, min: 0 },
18	    lessons: { type: [LessonProgressSchema], default: undefined },
19	    lessonReadAt: { type: Date }
20	  },
21	  { _id: false }
22	);
23	
24	type Doc = Document & Omit<IUserRoadmapProgress, '_id'>;
25	
26	const UserRoadmapProgressSchema = new Schema<Doc>(
27	  {
28	    userId: { type: Schema.Types.ObjectId, ref: 'User', required: true, index: true },
29	    subjectId: { type: Schema.Types.ObjectId, ref: 'Subject', required: true, index: true },
30	    canonicalVersion: { type: Number, required: true, min: 1 },
31	    nodes: { type: [NodeProgressSchema], default: [] }
32	  },
33	  { timestamps: true, collection: 'user_roadmap_progress' }
34	);
35	
36	UserRoadmapProgressSchema.index({ userId: 1, subjectId: 1 }, { unique: true });
37	
38	export const UserRoadmapProgress: Model<Doc> = mongoose.model<Doc>(
39	  'UserRoadmapProgress',
40	  UserRoadmapProgressSchema
41	);
42	
43	function normalizeLessons(raw: unknown): IUserLessonProgress[] | undefined {
44	  if (!Array.isArray(raw)) return undefined;
45	  const out: IUserLessonProgress[] = [];
46	  for (const item of raw) {
47	    if (!item || typeof item !== 'object') continue;
48	    const l = item as Record<string, unknown>;
49	    const lessonId = typeof l.lessonId === 'string' ? l.lessonId : '';
50	    if (!lessonId) continue;
51	    const readAt = l.readAt instanceof Date ? l.readAt : undefined;
52	    out.push({ lessonId, ...(readAt ? { readAt } : {}) });
53	  }
54	  return out.length > 0 ? out : undefined;
55	}
56	
57	/** Нормализация документа после смены схемы (старые поля progressStatus / attemptsCount) */
58	export function normalizeStoredNodeProgress(raw: unknown): IUserRoadmapNodeProgress {
59	  const p = raw as Record<string, unknown> & { nodeId?: string };
60	  const nodeId = String(p.nodeId ?? '');
61	  const lessonReadAt = p.lessonReadAt instanceof Date ? p.lessonReadAt : undefined;
62	  const lessons = normalizeLessons(p.lessons);
63	
64	  if (typeof p.mastered === 'boolean' && typeof p.bestScore === 'number') {
65	    const low =
66	      typeof p.lowScoreFailCount === 'number' && p.lowScoreFailCount >= 0
67	        ? Math.min(100, Math.floor(p.lowScoreFailCount))
68	        : 0;
69	    return {
70	      nodeId,
71	      mastered: p.mastered,
72	      bestScore: p.bestScore,
73	      ...(low > 0 ? { lowScoreFailCount: low } : {}),
74	      ...(lessons ? { lessons } : {}),
75	      ...(lessonReadAt ? { lessonReadAt } : {})
76	    };
77	  }
78	
79	  const legacyStatus = p.progressStatus as string | undefined;
80	  const legacyBest = typeof p.bestScore === 'number' ? p.bestScore : 0;
81	  const mastered = legacyStatus === 'mastered' || (typeof p.mastered === 'boolean' && p.mastered);
82	  return {
83	    nodeId,
84	    mastered,
85	    bestScore: mastered ? Math.max(legacyBest, 70) : legacyBest,
86	    ...(typeof p.lowScoreFailCount === 'number' && p.lowScoreFailCount > 0
87	      ? { lowScoreFailCount: p.lowScoreFailCount }
88	      : {}),
89	    ...(lessons ? { lessons } : {}),
90	    ...(lessonReadAt ? { lessonReadAt } : {})
91	  };
92	}
