1	import { SoloAttempt, Subject, User } from '../models';
2	import { roadmapService } from './roadmap.service';
3	import { getLearnerSubjectIds } from '../utils/learnerSubjectAccess.util';
4	
5	export interface IProfileStats {
6	  /** Стрик ежедневных кахутов (дней подряд с ranked-попыткой) */
7	  dailyStreak: number;
8	  /** Темы: изучено / всего по предметам пользователя */
9	  topics: { studied: number; total: number };
10	  /** Предметы: выбрано / всего (main обязательны + 2 профильных, если пара выбрана) */
11	  subjects: { selected: number; total: number; hasProfileSubject: boolean };
12	}
13	
14	/**
15	 * PROFILE STATS SERVICE
16	 * Карточки профиля: стрик, изучено тем, выбрано предметов. Все три метрики считаются из
17	 * существующих данных (SoloAttempt / роадмап-прогресс / Subject), отдельных коллекций не вводим.
18	 */
19	class ProfileStatsService {
20	  async getProfileStats(userId: string): Promise<IProfileStats> {
21	    const [dailyStreak, topics, subjects] = await Promise.all([
22	      this.computeDailyStreak(userId),
23	      this.computeTopicsStudied(userId),
24	      this.computeSubjectsSelected(userId)
25	    ]);
26	    return { dailyStreak, topics, subjects };
27	  }
28	
29	  /** Дней подряд с ranked-кахутом, заканчивая сегодня (или вчера, если сегодня ещё не играл). */
30	  async computeDailyStreak(userId: string): Promise<number> {
31	    const attempts = await SoloAttempt.find({ userId, attemptType: 'ranked' })
32	      .select('createdAt')
33	      .sort({ createdAt: -1 })
34	      .lean();
35	    if (attempts.length === 0) return 0;
36	
37	    const dayKeys = new Set(
38	      attempts.map((a) => this.dayKey(a.createdAt as Date)).filter(Boolean) as string[]
39	    );
40	
41	    let cursor = this.startOfUtcDay(new Date());
42	    // если сегодня ещё нет активности — стрик может «висеть» со вчера
43	    if (!dayKeys.has(this.dayKey(cursor))) {
44	      cursor = this.addDays(cursor, -1);
45	      if (!dayKeys.has(this.dayKey(cursor))) return 0;
46	    }
47	
48	    let streak = 0;
49	    while (dayKeys.has(this.dayKey(cursor))) {
50	      streak += 1;
51	      cursor = this.addDays(cursor, -1);
52	    }
53	    return streak;
54	  }
55	
56	  /** Изучено (mastered) / всего тем по всем предметам пользователя (main + профильная пара). */
57	  async computeTopicsStudied(userId: string): Promise<{ studied: number; total: number }> {
58	    const subjectIds = await getLearnerSubjectIds(userId);
59	    let studied = 0;
60	    let total = 0;
61	    for (const sid of subjectIds) {
62	      const { nodesTotal, nodesMastered } = await roadmapService.getProgressCounts(userId, sid);
63	      total += nodesTotal;
64	      studied += nodesMastered;
65	    }
66	    return { studied, total };
67	  }
68	
69	  /**
70	   * Предметы: выбрано / всего.
71	   * Все main-предметы обязательны (всегда «выбраны»); профильных выбирается 2 (если пара выбрана).
72	   * total = все main + все профильные. hasProfileSubject — выбрана ли профильная пара.
73	   */
74	  async computeSubjectsSelected(
75	    userId: string
76	  ): Promise<{ selected: number; total: number; hasProfileSubject: boolean }> {
77	    const user = await User.findById(userId).select('profileSubjectPairId').lean();
78	    const hasProfileSubject = !!user?.profileSubjectPairId;
79	
80	    const [mainTotal, profileTotal] = await Promise.all([
81	      Subject.countDocuments({ subjectKind: { $ne: 'profile' } }),
82	      Subject.countDocuments({ subjectKind: 'profile' })
83	    ]);
84	
85	    const selected = mainTotal + (hasProfileSubject ? 2 : 0);
86	    const total = mainTotal + profileTotal;
87	    return { selected, total, hasProfileSubject };
88	  }
89	
90	  // ==================== private ====================
91	
92	  private startOfUtcDay(date: Date): Date {
93	    const d = new Date(date);
94	    d.setUTCHours(0, 0, 0, 0);
95	    return d;
96	  }
97	
98	  private addDays(date: Date, days: number): Date {
99	    const d = new Date(date);
100	    d.setUTCDate(d.getUTCDate() + days);
101	    return d;
102	  }
103	
104	  private dayKey(date: Date | undefined): string {
105	    if (!date) return '';
106	    return new Date(date).toISOString().slice(0, 10);
107	  }
108	}
109	
110	export const profileStatsService = new ProfileStatsService();
