1	import { Subject, User, ProfileSubjectPair } from '../models';
2	import { AppError } from '../utils';
3	/** Порядок и объём как в едином национальном тестировании (Казахстан) — в формате вопросов ЕНТ */
4	const MAIN_TRIAL_TITLES = [
5	  'История Казахстана',
6	  'Математическая грамотность',
7	  'Грамотность чтения'
8	] as const;
9	
10	const MAIN_TRIAL_BLOCKS: Array<{
11	  questionCount: number;
12	  blockLabel: string;
13	}> = [
14	  { questionCount: 20, blockLabel: 'История Казахстана: 20 вопросов (20 баллов)' },
15	  { questionCount: 10, blockLabel: 'Математическая грамотность: 10 вопросов (10 баллов)' },
16	  { questionCount: 10, blockLabel: 'Грамотность чтения: 10 вопросов (10 баллов)' }
17	];
