1	/**
2	 * Бизнес-правила Roadmap (MVP).
3	 * Rule 2: mastered если bestScore ≥ THRESHOLD (глобальный best по узлу).
4	 * Порог и коды причин — единственный источник правды для сервиса.
5	 */
6	
7	/** Минимальный процент для засчитывания узла как освоенного при обычных тестах по узлу */
8	export const ROADMAP_MASTERY_THRESHOLD_PERCENT = 70;
9	
10	/** Порог «освоено» по результатам пробного тестирования (на главу) */
11	export const ROADMAP_TRIAL_MASTERY_THRESHOLD_PERCENT = 80;
12	
13	/**
14	 * Порог для теста по узлу карты: результат ниже — считается неудачной попыткой (счётчик lowScoreFailCount).
15	 * Совпадает с «пробником» 80%.
16	 */
17	export const ROADMAP_KNOWLEDGE_TEST_PASS_PERCENT = ROADMAP_TRIAL_MASTERY_THRESHOLD_PERCENT;
18	
19	/** Сколько неудачных попыток (< порога) подряд — блокируем повтор теста до кнопки «Освоил» */
20	export const ROADMAP_MAX_KNOWLEDGE_TEST_FAILS_BEFORE_BLOCK = 3;
21	
22	/** Сколько последних попыток учитывать для bestScore (если включите rolling window; сейчас используем глобальный best) */
23	export const ROADMAP_BEST_SCORE_WINDOW_N = 3;
24	
25	/** Сколько узлов отдавать в списке рекомендаций */
26	export const ROADMAP_TOP_K_RECOMMENDATIONS = 3;
27	
28	export type RecommendedReasonCode =
29	  | 'CONTINUE_IN_PROGRESS'
30	  | 'UNLOCKS_NEXT_TOPICS'
31	  | 'LOW_MASTERY'
32	  | 'PART_OF_MAIN_PATH'
33	  | 'NOT_STARTED';
34	
35	/** masteryScore 0..1 из bestScore процента */
36	export function scorePercentToMasteryScore(scorePercent: number): number {
37	  return Math.min(1, Math.max(0, scorePercent / 100));
38	}
39	
40	export function isMasteredByBestScore(bestScorePercent: number): boolean {
41	  return bestScorePercent >= ROADMAP_MASTERY_THRESHOLD_PERCENT;
42	}
43	
44	export function isMasteredByTrialScore(scorePercent: number): boolean {
45	  return scorePercent >= ROADMAP_TRIAL_MASTERY_THRESHOLD_PERCENT;
46	}
