40	function defaultProgress(nodeId: string): IUserRoadmapNodeProgress {
41	  return { nodeId, mastered: false, bestScore: 0, lowScoreFailCount: 0 };
42	}
43	
44	function progressMap(nodes: IUserRoadmapNodeProgress[]): Map<string, IUserRoadmapNodeProgress> {
45	  return new Map(nodes.map((n) => [n.nodeId, n]));
46	}
47	
48	function masteredSet(
49	  canonicalNodes: ICanonicalRoadmapNode[],
50	  progressByNode: Map<string, IUserRoadmapNodeProgress>
51	): Set<string> {
52	  const set = new Set<string>();
53	  for (const cn of canonicalNodes) {
54	    const p = progressByNode.get(cn.nodeId);
55	    if (p?.mastered) set.add(cn.nodeId);
56	  }
57	  return set;
58	}
59	
60	function availabilityForNode(
61	  node: ICanonicalRoadmapNode,
62	  mastered: Set<string>
63	): RoadmapAvailability {
64	  if (node.prerequisites.length === 0) return 'available';
65	  const allDone = node.prerequisites.every((id) => mastered.has(id));
66	  return allDone ? 'available' : 'locked';
67	}
68	
69	function unlocksCount(
70	  nodeId: string,
71	  canonicalNodes: ICanonicalRoadmapNode[],
72	  mastered: Set<string>
73	): number {
74	  const hypothetical = new Set(mastered);
75	  hypothetical.add(nodeId);
76	  let count = 0;
77	  for (const n of canonicalNodes) {
78	    if (hypothetical.has(n.nodeId)) continue;
79	    if (n.prerequisites.length === 0) continue;
80	    const wasLocked = !n.prerequisites.every((id) => mastered.has(id));
81	    const nowAvail = n.prerequisites.every((id) => hypothetical.has(id));
82	    if (wasLocked && nowAvail) count++;
83	  }
84	  return count;
85	}
