99	function compareFrontier(
100	  a: { node: ICanonicalRoadmapNode; p: IUserRoadmapNodeProgress; unlocks: number },
101	  b: { node: ICanonicalRoadmapNode; p: IUserRoadmapNodeProgress; unlocks: number }
102	): number {
103	  const aInProg = a.p.bestScore > 0 && !a.p.mastered ? 1 : 0;
104	  const bInProg = b.p.bestScore > 0 && !b.p.mastered ? 1 : 0;
105	  if (bInProg !== aInProg) return bInProg - aInProg;
106	  if (b.unlocks !== a.unlocks) return b.unlocks - a.unlocks;
107	  return a.p.bestScore - b.p.bestScore;
108	}
