1048	    const subject = await Subject.findById(subjectId).lean();
1049	    if (!subject) throw AppError.notFound('Subject not found');
1050	
1051	    const ktp = await KtpCatalog.findOne({ subjectId }).lean<IKtpCatalog>();
1052	    if (!ktp || !Array.isArray(ktp.topics) || ktp.topics.length === 0) {
1053	      throw AppError.badRequest('Сначала заведите справочник КТП по предмету (раздел «КТП»)');
1054	    }
1055	
1056	    const nodes = buildKtpCanonicalNodes(subject, ktp);
1057	    if (nodes.length === 0) {
