1060	      );
1061	    }
1062	    assertValidCanonicalNodes(nodes);
1063	
1064	    const subjectOid = new mongoose.Types.ObjectId(subjectId);
1065	    // Снимок не нужен (live-сборка приоритетна): удаляем устаревшие ручные/старые записи.
1066	    await CanonicalRoadmap.deleteMany({ subjectId: subjectOid });
1067	
1068	    const newUpdatedAt = new Date();
