1	import { IQuestion, IUserAnswer } from '../types';
2	import { mapBookTopicToKtpNodeIds } from './roadmapKtp.util';
3	import { ROADMAP_TRIAL_MASTERY_THRESHOLD_PERCENT } from '../roadmap/roadmap.rules';
4	
5	type TopicKey = string;
6	
7	/**
8	 * Результаты пробника: узлы КТП, где в этом тесте ≥ порога (по умолчанию 80%) правильных.
9	 *
10	 * Считает корректность по (chapterId, topicId) из relatedContent, затем ФАНАУТИТ каждую
11	 * тему книги на все КТП-узлы (`ktp:*`), на которые она замаплена (Subject.Topic.ktpTopicIds).
12	 * Один узел КТП может получить вклад от нескольких тем книг — берём максимальный score.
13	 */
14	export function computeTrialTopicMasteryRows(
15	  subject: unknown,
16	  bookId: string,
17	  test: { subjectId?: unknown; questions: IQuestion[] },
18	  userAnswers: IUserAnswer[]
19	): Array<{ subjectId: string; nodeId: string; scorePercent: number }> {
20	  if (test.questions.length !== userAnswers.length) return [];
21	  const byTopic = new Map<TopicKey, { correct: number; total: number; chapterId: string; topicId: string }>();
22	
23	  for (let i = 0; i < test.questions.length; i++) {
24	    const q = test.questions[i];
25	    const ua = userAnswers[i];
26	    const rc = q.relatedContent;
27	    if (!rc?.topicId || !rc?.chapterId) continue;
28	    const chapterId = rc.chapterId.toString();
29	    const topicId = rc.topicId.toString();
30	    const key = `${chapterId}\x1f${topicId}`;
31	    const acc = byTopic.get(key) ?? { correct: 0, total: 0, chapterId, topicId };
32	    acc.total += 1;
33	    if (ua.isCorrect) acc.correct += 1;
34	    byTopic.set(key, acc);
35	  }
36	
37	  const sid = (subject as { _id?: unknown })._id;
38	  const subjectId = sid ? String(sid) : String(test.subjectId ?? '');
39	
40	  // Фанаут темы книги → КТП-узлы; дедуп по максимальному score на узел.
41	  const bestByNode = new Map<string, number>();
42	  for (const v of byTopic.values()) {
43	    if (v.total < 1) continue;
44	    const scorePercent = Math.round((v.correct / v.total) * 100);
45	    if (scorePercent < ROADMAP_TRIAL_MASTERY_THRESHOLD_PERCENT) continue;
46	    for (const nodeId of mapBookTopicToKtpNodeIds(subject, bookId, v.chapterId, v.topicId)) {
47	      const prev = bestByNode.get(nodeId) ?? 0;
48	      if (scorePercent > prev) bestByNode.set(nodeId, scorePercent);
49	    }
50	  }
51	
52	  const out: Array<{ subjectId: string; nodeId: string; scorePercent: number }> = [];
53	  for (const [nodeId, scorePercent] of bestByNode) {
54	    out.push({ subjectId, nodeId, scorePercent });
55	  }
56	  return out;
57	}
